#include <iostream>
#include <string>
#include <unordered_set>

string gcdOfStrings(string str1, string str2) {
    std::unordered_set<char> set;
    for (char c : str1) {
        set.insert(c);
    }
    for (char c : str2) {
        if (!set.count(c)) {
            return "";
        }
    }
    std::string result;
    int count = 0;
    for (char c : str1) {
        while (set.count(c) && count < str1.length()) {
            set.erase(c);
            count++;
        }
        result += c;
    }
    return result;
}
```

